var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"하아, 하…… 숨 차……","JPN":"はあ、は……きつい。","ENG":"*Huff...* *Huff...* I need to catch my breath...","TWN":"呼呼，呼…好累…"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L4_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"그래도 이제 더 달려들지는 않는 건가?","JPN":"でも、もう飛びかかってこないのね。","ENG":"But it seems like they've stopped chasing after us.","TWN":"他們好像沒有再撲過來？"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"그렇다면 여기가 기관실인 것 같은데…….","JPN":"だとすると、ここが機関室ってことだけど……","ENG":"That'll mean that this is the engine room...","TWN":"這麼說來，這裡應該就是駕駛室……"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"뭔가 생각했던 분위기와는 많이 다른걸.","JPN":"なんだか、思ってた雰囲気とはだいぶ違うな。","ENG":"It's a lot different from what I imagined it to be.","TWN":"和我想像中的感覺截然不同呢。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MORS_SHADOW_CA_QM","text":{"KOREA":"그럴 수밖에요.","JPN":"そうでしょう。","ENG":"Of course.","TWN":"那當然。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"이 곳은 제가 교단에 몸 담기 전 지냈던 시설이랍니다.","JPN":"ここは、私が教団に所属する前に暮らしていた施設です。","ENG":"This is the facility where I was before I joined the church.","TWN":"這裡是我加入教團之前住過的地方。"},"stage":{"bg":"BASEMENT","bgm":"THEMA_SECURITY_AGENT_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L11_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"보이지 않아도 알 수 있을 만큼, 무척이나 삭막한 공간이었지요.","JPN":"見えなくてもわかるほど、とても殺風景な空間でした。","ENG":"Although I could not see, I could tell how dreary of a place it was.","TWN":"我雖然看不見，但依然能感受到這裡的淒涼。"},"stage":{"bg":"BASEMENT","bgm":"THEMA_SECURITY_AGENT_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"마에스트로…….","JPN":"マエストロ……","ENG":"Maestra...","TWN":"指揮家……"},"stage":{"bg":"BASEMENT","bgm":"THEMA_SECURITY_AGENT_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"매주마다, 미사를 치르는 날에는 고기 타는 악취가 시설을 맴돌았지요.","JPN":"毎週、ミサの日には肉が焦げる悪臭が施設を漂っていました。","ENG":"Every week, when mass was held, this place would stink of burning meat.","TWN":"每週舉行彌撒聖祭時，這裡都會充斥著皮肉燒焦的惡臭。"},"stage":{"bg":"BASEMENT","bgm":"THEMA_SECURITY_AGENT_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L15_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"교리를 가르치러 온 사제들은 이교도들의 영혼을 정화하면서 나온 나쁜 마음 탓이라고 하였지만….","JPN":"教理を教えに来た司祭は、異教徒の魂を浄化していく中で出る、悪い心のせいであると言っていましたが……","ENG":"The priests who came to teach us the doctrine told us that it was the smell of malice that was extracted as the heretics' souls were purified, but I knew the truth...","TWN":"來傳授教義的祭司們說，那是淨化異教徒們的靈魂時，散發出的惡念之氣，但是……"},"stage":{"bg":"BASEMENT","bgm":"THEMA_SECURITY_AGENT_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"저는 태어날 때부터 앞이 보이지 않는 대신에 남들보다 귀가 밝았습니다.","JPN":"私は生まれた時から目が見えない代わりに、人より耳が良かったのです。","ENG":"Although I was blind from birth, I had good hearing.","TWN":"我雖天生眼盲，但從小就有著超乎常人的聽力。"},"stage":{"bg":"BASEMENT","bgm":"THEMA_SECURITY_AGENT_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"사제들의 부름을 받고 간 우리의 친구와 부모들이 강철 문을 손톱으로 긁어대던 소음.","JPN":"司祭に呼ばれて出て行った友だちとその親が、鋼鉄のドアを爪で引っ掻く騒音。","ENG":"The sound of my friends and their parents who were called in by the priests clawing against the iron door.","TWN":"被祭司們叫去的朋友，和他們的父母用指甲拼命抓鐵門發出的噪音，"},"stage":{"bg":"BASEMENT","bgm":"THEMA_SECURITY_AGENT_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"살과 뼈가 타들어가는 소음.","JPN":"肉と骨が燃えてゆく騒音。","ENG":"The crackling sound of scorching flesh and bone.","TWN":"皮肉筋骨被燒焦的噪音，"},"stage":{"bg":"BASEMENT","bgm":"THEMA_SECURITY_AGENT_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"그리고 자신들의 순번이 아직 오지 않았다고 외면하는 이들의 심장 박동까지.","JPN":"そして、まだ自分たちの順番ではないと現実に目を背ける者たちの心臓の音まで。","ENG":"And the pounding sound of hearts from those who turned a blind eye because their turn had not yet come.","TWN":"還有那些害怕輪到自己的人，他們的心跳聲，"},"stage":{"bg":"BASEMENT","bgm":"THEMA_SECURITY_AGENT_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"모두 듣고 있었지요.","JPN":"全部聞いていたのです。","ENG":"I heard it all.","TWN":"我都聽得非常清楚。"},"stage":{"bg":"BASEMENT","bgm":"THEMA_SECURITY_AGENT_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L24_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"환영합니다. 그리고 반갑습니다.","JPN":"ようこそ、お会いできて嬉しいです。","ENG":"Welcome. A pleasure to meet you.","TWN":"歡迎，很高興見到你。"},"stage":{"bg":"BASEMENT","bgm":"THEMA_SECURITY_AGENT_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"이런 형태로 대면하게 될 줄은 몰랐어요. 레아 슈나이더.","JPN":"このような形で対面することになるとは思ってもいませんでした。レア・シュナイダー。","ENG":"I did not expect to face you like this, Leah Schneider.","TWN":"沒想到會以這種形態與你相見，蕾亞·修奈德。"},"stage":{"bg":"BASEMENT","bgm":"THEMA_SECURITY_AGENT_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"아니, 정확히는 <color=#ffd34c>저의 그림자</color>가 남긴 여분의 의식이라고 불러 드려야 할지요.","JPN":"いいえ、正確には<color=#ffd34c>私の残滓</color>が残した余分の意識とでもお呼びするべきでしょうか。","ENG":"Or, should I call you the remaining consciousness that <color=#ffd34c>my Shadow</color> left?","TWN":"不，準確地說，你應該是<color=#ffd34c>我的殘影</color>殘存的意識。"},"stage":{"bg":"BASEMENT","bgm":"THEMA_SECURITY_AGENT_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_LAUGH"}}}},{"id":"L27_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"……그러니까 너는 그림자의 원본이란 말이지.","JPN":"……つまり君はネキティアのオリジナルってわけだね。","ENG":"...Then you must be the original of the Shadow.","TWN":"……也就是說，你就是暗影的本體。"},"stage":{"bg":"BASEMENT","bgm":"THEMA_SECURITY_AGENT_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_LAUGH"}}}},{"id":"L28_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"그녀에게 인간으로서의 저는 처음으로 실패한 경험인 셈이지요.","JPN":"彼女にとって人間としての私は、初めて失敗した経験なのです。","ENG":"To her, the human form of me was her first experience with failure.","TWN":"對她而言，人類形態的我是她的第一次失敗經歷。"},"stage":{"bg":"BASEMENT","bgm":"THEMA_SECURITY_AGENT_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"뜻을 이루기 전에 모든 것을 잃고, 역병에 사로잡힌 자가 아니던가요.","JPN":"望みを叶える前にすべてを失い、疫病に囚われたのですから。","ENG":"Am I not the one who lost everything before achieving the goal and was consumed by the plague?","TWN":"她沒能實現心願卻失去一切，還遭遇到瘟疫的侵蝕。"},"stage":{"bg":"BASEMENT","bgm":"THEMA_SECURITY_AGENT_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"네가 어떻게 생각하든 상관없어.","JPN":"君がどう考えようと、私には関係ない。","ENG":"I don't care what you think.","TWN":"你怎麼想都無所謂。"},"stage":{"bg":"BASEMENT","bgm":"THEMA_SECURITY_AGENT_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L34_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"내숭 떨지 말아 줘. 너는 그림자가 되기 이전에도 충분히 미쳐 있었으니까.","JPN":"ネコ被らないでくれる？　君はシャドウになる前から十分に狂っていたよ。","ENG":"Stop being coy with me. You were crazy enough even before you became a Shadow.","TWN":"但別再狡辯了，在變成暗影之前，你就不是一個正常人。"},"stage":{"bg":"BASEMENT","bgm":"THEMA_SECURITY_AGENT_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BASEMENT","bgm":"THEMA_SECURITY_AGENT_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"나는 여기서 내려야 해.","JPN":"私は列車を降りなくちゃならない。","ENG":"I need to get off this train.","TWN":"我要在這裡下車。"},"stage":{"bg":"BASEMENT","bgm":"THEMA_SECURITY_AGENT_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"그러니…. 잔말 하지 말고 열차를 세울 방법이나 말해.","JPN":"だから……余計な話はやめて、列車を止める方法を教えて。","ENG":"So... cut to the chase and tell me how to stop this train.","TWN":"所以……廢話少說，快告訴我怎樣才能讓列車停下。"},"stage":{"bg":"BASEMENT","bgm":"THEMA_SECURITY_AGENT_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"원하신다면야 그래야지요.","JPN":"それがお望みならば。","ENG":"If that is what you wish.","TWN":"既然你這麼說，我就告訴你吧。"},"stage":{"bg":"BASEMENT","bgm":"THEMA_SECURITY_AGENT_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_PRIDE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"그럼 부디 마음을 가다듬고 들어 주시길.","JPN":"それでは、どうか落ち着いてお聞きください。","ENG":"But please calm down and listen.","TWN":"請仔細聽我說。"},"stage":{"bg":"BASEMENT","bgm":"THEMA_SECURITY_AGENT_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"열차를 세울 방법은 없습니다.","JPN":"列車を止める方法は、ありません。","ENG":"There is no way to stop the train.","TWN":"讓列車停下的方法是不存在的。"},"stage":{"bg":"BASEMENT","bgm":"THEMA_SECURITY_AGENT_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_HATE"},"R":null}}}]`);export{e as default};